SELECT COUNT(*) AS total_applications
FROM visa_applications
WHERE visa_type_id = 1;

SELECT applicant_name
FROM visa_applications
WHERE applicant_nationality = 'American';

SELECT consulate_name
FROM consulates
WHERE consulate_name = 'TIRANA';

SELECT COUNT(state_id) AS number_of_states
FROM schengen_states
WHERE population > 5000000;

SELECT COUNT(*) AS number_of_consulates
FROM consulates
WHERE state_id = 1;
